cat > /tmp/mlint.mjs <<'EOF'
import fs from 'fs';
const files = process.argv.slice(2);
let problems = 0;
for (const f of files) {
  const txt = fs.readFileSync(f, 'utf8');
  const re = /```mermaid\n([\s\S]*?)```/g;
  let m, idx = 0;
  while ((m = re.exec(txt))) {
    idx++;
    const block = m[1];
    const lines = block.split('\n');
    const tag = `${f} block#${idx}`;
    // 1) space before shape used as edge source/standalone: `ID {`, `ID [`, `ID (`
    lines.forEach((l, i) => {
      if (/^\s*[A-Za-z0-9_]+\s+[\{\[\(]"/.test(l)) {
        console.log(`[SPACE-SHAPE] ${tag} L${i+1}: ${l.trim()}`); problems++;
      }
    });
    // 2) raw '<' not part of <br or &lt; or </
    lines.forEach((l, i) => {
      const stripped = l.replace(/<br\s*\/?>/g,'').replace(/&lt;/g,'').replace(/<\//g,'');
      if (/[^&]<(?![a-zA-Z\/])/.test(stripped) && /<[^b]/.test(stripped)) {
        // refine: any '<' remaining that isn't a known tag
        if (/</.test(stripped)) { console.log(`[RAW-LT] ${tag} L${i+1}: ${l.trim()}`); problems++; }
      }
    });
    // 3) conflicting shapes for same node id
    const shapes = {}; // id -> Set of shapeChar
    const shapeRe = /\b([A-Za-z0-9_]+)(\{|\[\[|\[|\(\(|\(|\{\{|>)\s*"/g;
    let s;
    while ((s = shapeRe.exec(block))) {
      const id = s[1], sh = s[2];
      (shapes[id] ||= new Set()).add(sh);
    }
    for (const [id, set] of Object.entries(shapes)) {
      if (set.size > 1) { console.log(`[DUP-SHAPE] ${tag}: node '${id}' defined with shapes {${[...set].join(', ')}}`); problems++; }
    }
    // 4) class statement with comma in className (two classes)
    lines.forEach((l, i) => {
      const cm = l.match(/^\s*class\s+[A-Za-z0-9_,]+\s+([A-Za-z0-9_,]+)\s*$/);
      if (cm && cm[1].includes(',')) { console.log(`[MULTI-CLASS] ${tag} L${i+1}: ${l.trim()}`); problems++; }
    });
    // 5) balanced quotes per line
    lines.forEach((l, i) => {
      const q = (l.match(/"/g) || []).length;
      if (q % 2 !== 0) { console.log(`[ODD-QUOTE] ${tag} L${i+1}: ${l.trim()}`); problems++; }
    });
  }
}
console.log(problems === 0 ? '\nLINT OK — no structural issues found' : `\n${problems} potential issue(s)`);
EOF
