input.script:
export const meta = {
  name: 'problem-statement-coverage',
  description: 'Traceability analysis: does docs/scenarios-flowchart.md fulfill & show every question/problem/requirement from the take-home problem statement? Extract -> trace -> adversarially verify -> report.',
  phases: [
    { title: 'Extract', detail: 'Atomize every requirement/question/problem from the problem statement' },
    { title: 'Trace', detail: 'Map each requirement to flowchart coverage with evidence' },
    { title: 'Verify', detail: 'Adversarially confirm each coverage claim against the actual flowchart file' },
    { title: 'Report', detail: 'Reconcile, write coverage report, answer the question' },
  ],
}

const ROOT = '/Users/raunaksingh/Documents/realfast/insurance'
const FLOWCHART = ROOT + '/docs/scenarios-flowchart.md'
const OUT = ROOT + '/docs/problem-statement-coverage.md'

const SOURCES = `Requirements source of truth:
- ${ROOT}/project-docs/problem_statement.md
- ${ROOT}/project-docs/candidate_assignment_instructions.md
Artifact UNDER TEST (the thing we judge coverage against):
- ${FLOWCHART}  (5 Mermaid flowcharts: 1 Intake, 2 Per-line adjudication pipeline, 3 Aggregation, 4 Dispute re-adjudication, 5 Status-transition lifecycle + a 45-row scenario coverage matrix)
Cross-reference (where NON-flowchart concerns may legitimately live):
- ${ROOT}/docs/domain-model.md  ${ROOT}/docs/adjudication-plan.md  ${ROOT}/docs/decisions.md  ${ROOT}/docs/erd.md  ${ROOT}/PRD.md`

const REQS_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['requirements','notes'],
  properties: {
    requirements: { type: 'array', items: { type: 'object', additionalProperties: false,
      required: ['id','requirement','category','source','flowchartExpectation'],
      properties: {
        id: { type: 'string', description: 'short id e.g. Q1, WS3, SCOPE2, SIGNAL4, FLOW2' },
        requirement: { type: 'string', description: 'the atomic requirement/question/problem, quoted or tightly paraphrased' },
        category: { type: 'string', enum: ['interesting-problem','working-system-capability','in-scope-item','context-flow-step','evaluation-signal','process-deliverable'] },
        source: { type: 'string', description: 'file:line' },
        flowchartExpectation: { type: 'string', description: 'what you would expect to SEE in a flowchart if this is covered; or "N/A for flowchart — belongs in <doc>" with reason' },
      } } },
    notes: { type: 'string' },
  },
}

const TRACE_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['matrix','summary'],
  properties: {
    matrix: { type: 'array', items: { type: 'object', additionalProperties: false,
      required: ['id','verdict','evidence','alsoCoveredIn','comment'],
      properties: {
        id: { type: 'string' },
        verdict: { type: 'string', enum: ['SHOWN','PARTIAL','NOT_SHOWN','N/A_FLOWCHART'] },
        evidence: { type: 'string', description: 'EXACT diagram # + node/edge label or matrix row in the flowchart; "none" if absent' },
        alsoCoveredIn: { type: 'string', description: 'other doc+section that covers it, if any' },
        comment: { type: 'string' },
      } } },
    summary: { type: 'string' },
  },
}

const VERIFY_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['id','independentVerdict','evidenceFound','agreesWithTrace','note'],
  properties: {
    id: { type: 'string' },
    independentVerdict: { type: 'string', enum: ['SHOWN','PARTIAL','NOT_SHOWN','N/A_FLOWCHART'] },
    evidenceFound: { type: 'string', description: 'the EXACT node/edge/section you located, verbatim; or "none found"' },
    agreesWithTrace: { type: 'boolean' },
    note: { type: 'string' },
  },
}

const SYNTH_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['filePath','totals','gaps','divergences','headlineVerdict','summary'],
  properties: {
    filePath: { type: 'string' },
    totals: { type: 'object', additionalProperties: true, description: 'counts by final verdict' },
    gaps: { type: 'array', items: { type: 'string' } },
    divergences: { type: 'array', items: { type: 'string' }, description: 'deliberate divergences from the problem statement (e.g. PAID state dropped)' },
    headlineVerdict: { type: 'string', description: 'direct answer: are the problem-statement questions/problems fulfilled AND shown in the flowchart?' },
    summary: { type: 'string' },
  },
}

// ---------------- EXTRACT ----------------
phase('Extract')
const extract = await agent(`You are auditing whether a scenario flowchart fulfills a take-home assignment's requirements. FIRST, atomize the requirements.

${SOURCES}

Read BOTH project-docs files fully. Extract EVERY atomic requirement, question, and problem, being exhaustive. Make sure to include:
- The 5 "interesting problems" (coverage-rule modeling; tracking usage against limits; the 5-line-item mixed-outcome case; explaining WHY something was denied; claim vs line-item state machine).
- The "A working system" bullets (accepts submissions w/ line items; applies coverage rules -> payable; moves claims through lifecycle states; produces explanations for every decision; has an interface).
- The "In scope" items and the "What We're Looking For" evaluation signals (domain decomposition, rule representation, state management, edge-case thinking incl. partial approvals / limit exhaustion / RETROACTIVE CHANGES, explanation capability).
- The Context flow steps, INCLUDING the lifecycle "submitted -> under review -> approved/denied -> PAID" (note 'paid' explicitly) and PHI sensitivity, and "members can dispute decisions".
For each, classify it and state what you'd expect to SEE in a flowchart if covered — or mark "N/A for flowchart" and name the doc it belongs in (e.g. interface/REST is a system concern, coverage-rule representation is a data-model/ERD concern). Output via StructuredOutput.`,
  { agentType: 'general-purpose', schema: REQS_SCHEMA, label: 'extract:requirements' })
if (!extract) { log('Extract failed'); return { error: 'extract failed' } }
const reqs = extract.requirements || []
log(`Extracted ${reqs.length} atomic requirements`)

// ---------------- TRACE ----------------
phase('Trace')
const reqsJson = JSON.stringify(reqs)
const trace = await agent(`Map each requirement to its coverage IN THE FLOWCHART specifically.

${SOURCES}

Requirements (JSON):
${reqsJson}

Read ${FLOWCHART} carefully (all 5 diagrams + the scenario coverage matrix). For EACH requirement id, assign a verdict about THE FLOWCHART:
- SHOWN: explicitly represented by a node/edge/branch/matrix-row — cite the EXACT diagram # and node/label/row.
- PARTIAL: partially represented (say what's missing).
- NOT_SHOWN: not in the flowchart at all.
- N/A_FLOWCHART: not a flowchart-type concern (e.g. interface, data-model, process deliverable) — then fill alsoCoveredIn with the doc/section that handles it.
Cross-reference the other docs ONLY to fill alsoCoveredIn (where-else-covered); the verdict itself is strictly about the flowchart. Quote node labels verbatim as evidence. Output via StructuredOutput.`,
  { agentType: 'general-purpose', schema: TRACE_SCHEMA, label: 'trace:matrix' })
if (!trace) { log('Trace failed'); return { error: 'trace failed', extract } }
const traceById = {}
for (const row of (trace.matrix || [])) traceById[row.id] = row
log(`Traced ${trace.matrix?.length || 0} rows — adversarially verifying each`)

// ---------------- VERIFY (adversarial, per requirement) ----------------
phase('Verify')
const verifies = (await parallel(reqs.map(r => () => {
  const tr = traceById[r.id] || { verdict: 'NOT_SHOWN', evidence: 'none' }
  return agent(`Adversarially verify one coverage claim. Do NOT trust the prior verdict — confirm it independently against the actual file.

Requirement [${r.id}] (${r.category}): ${r.requirement}
What a flowchart should show for it: ${r.flowchartExpectation}
PRIOR (unverified) verdict: ${tr.verdict} — cited evidence: ${tr.evidence}

Read ${FLOWCHART} yourself. Locate (or fail to locate) the exact node/edge/branch/matrix-row. Rules:
- Return SHOWN only if you can quote a specific node/edge/section that genuinely represents it.
- If you cannot point to specific content, return NOT_SHOWN or PARTIAL — default to the weaker verdict when uncertain.
- Use N/A_FLOWCHART only if it is genuinely not a flowchart concern.
Return your INDEPENDENT verdict, the exact evidence you found (verbatim) or "none found", whether you agree with the prior verdict, and a short note. Output via StructuredOutput.`,
    { agentType: 'general-purpose', schema: VERIFY_SCHEMA, label: `verify:${r.id}`, phase: 'Verify' })
}))).filter(Boolean)
const disagreements = verifies.filter(v => v && v.agreesWithTrace === false)
log(`Verified ${verifies.length} requirements — ${disagreements.length} disagreements with the trace`)

// ---------------- REPORT ----------------
phase('Report')
const verifyJson = JSON.stringify(verifies)
const synth = await agent(`Produce the final coverage report answering: "Are the questions/problems from the problem statement FULFILLED and SHOWN in the flowchart diagram?"

${SOURCES}

Requirements (JSON):
${reqsJson}

Trace matrix (JSON):
${JSON.stringify(trace.matrix)}

Adversarial verification per requirement (JSON) — the VERIFIER WINS on any disagreement with the trace:
${verifyJson}

Reconcile: for each requirement, final verdict = the verifier's independentVerdict (flag rows where trace and verifier disagreed). Then WRITE ${OUT} with the Write tool, containing:
# Problem-Statement Coverage Analysis — Scenario Flowchart
> one-line scope note.
## Headline verdict  (directly answer the question, with the count of fulfilled-and-shown vs gaps)
## Traceability matrix  — table: ID | Requirement | Category | Flowchart verdict | Evidence (diagram/node) | Also covered in
## Gaps & partials  — each NOT_SHOWN/PARTIAL that SHOULD be in the flowchart, with severity (high/med/low) + a concrete recommendation (which diagram to add a node/branch to).
## Deliberate divergences from the problem statement  — e.g. the statement lists a "paid" lifecycle state but the design dropped PAID (decision #14); the flowchart correctly omits it — call these out as conscious trade-offs to mention to reviewers, NOT bugs.
## Items that are N/A for a flowchart  — and where they ARE covered (interface, coverage-rule representation, etc.).
After writing, return filePath, totals (counts by final verdict), gaps (list), divergences (list), headlineVerdict, and summary.`,
  { agentType: 'octo:droids:octo-docs-architect', schema: SYNTH_SCHEMA, label: 'report:synthesize' })
if (!synth) { log('Report failed'); return { error: 'report failed', extract, trace, verifies } }

return {
  filePath: synth.filePath,
  totals: synth.totals,
  headlineVerdict: synth.headlineVerdict,
  gaps: synth.gaps,
  divergences: synth.divergences,
  traceVsVerifyDisagreements: disagreements.length,
  requirementCount: reqs.length,
  summary: synth.summary,
}

